import{A as e,f as t,h as n,t as r}from"./chunks/plugin-vue_export-helper.I53torQa.js";var i=JSON.parse(`{"title":"MMEngine 开发使用指南","description":"提供 MMEngine 深度学习训练引擎的开发使用指南与最佳实践","frontmatter":{"title":"MMEngine 开发使用指南","description":"提供 MMEngine 深度学习训练引擎的开发使用指南与最佳实践"},"headers":[],"relativePath":"distributed/mmengine/index.md","filePath":"distributed/mmengine/index.md","lastUpdated":1782803909000}`),a={name:`distributed/mmengine/index.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="mmengine-开发使用指南" tabindex="-1">MMEngine 开发使用指南 <a class="header-anchor" href="#mmengine-开发使用指南" aria-label="Permalink to “MMEngine 开发使用指南”">​</a></h1><h2 id="_1-介绍" tabindex="-1">1. 介绍 <a class="header-anchor" href="#_1-介绍" aria-label="Permalink to “1. 介绍”">​</a></h2><p>MMEngine 是一个基于 PyTorch 实现的深度学习模型训练基础库，支持在 Linux、Windows、macOS 上运行。它具有如下三个特性：</p><ol><li><strong>通用且强大的执行器</strong>： <ul><li>支持用少量代码训练不同的任务，例如仅使用 80 行代码就可以训练 ImageNet （原始 PyTorch 示例需要 400 行）。</li><li>轻松兼容流行的算法库（如 TIMM、TorchVision 和 Detectron2）中的模型。</li></ul></li><li><strong>接口统一的开放架构</strong>： <ul><li>使用统一的接口处理不同的算法任务，例如实现一个方法并应用于所有兼容模型。</li><li>上下游对接更加统一便捷，在为上层算法库提供统一抽象的同时，支持多种后端设备。目前 MMEngine 支持 Nvidia CUDA、Mac MPS、AMD、MLU 等设备进行模型训练。</li></ul></li><li><strong>可定制的训练流程</strong>： <ul><li>定义了&quot;乐高&quot;式的训练流程。</li><li>提供了丰富的组件和策略。</li><li>使用不同等级的 API 控制训练过程。</li></ul></li></ol><h2 id="_2-模块介绍" tabindex="-1">2. 模块介绍 <a class="header-anchor" href="#_2-模块介绍" aria-label="Permalink to “2. 模块介绍”">​</a></h2><img src="https://user-images.githubusercontent.com/40779233/187156277-7c5d020b-7ba6-421b-989d-2990034ff8cc.png" alt="模块关系" style="zoom:50%;"><p>MMEngine 将训练过程中涉及的组件和它们的关系进行了抽象，如上图所示。不同算法库中的同类型组件具有相同的接口定义。</p><h3 id="_2-1-核心模块与相关组件" tabindex="-1">2.1 核心模块与相关组件 <a class="header-anchor" href="#_2-1-核心模块与相关组件" aria-label="Permalink to “2.1 核心模块与相关组件”">​</a></h3><p>训练引擎的核心模块是<a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/runner.html" target="_blank" rel="noreferrer">执行器（ Runner）</a>。执行器负责执行训练、测试和推理任务，并管理这些过程中所需的各个组件。在任务执行过程中的特定位置，执行器设置了<a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/hook.html" target="_blank" rel="noreferrer">钩子（ Hook）</a>，允许用户拓展、插入和执行自定义逻辑。执行器主要调用如下组件来完成训练和推理过程中的循环：</p><ul><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/dataset.html" target="_blank" rel="noreferrer">数据集（ Dataset）</a>：负责在训练、测试、推理任务中构建数据集，并将数据送给模型。实际使用过程中会被数据加载器（DataLoader）封装一层，数据加载器会启动多个子进程来加载数据。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/model.html" target="_blank" rel="noreferrer">模型（ Model）</a>：在训练过程中接受数据并输出 loss；在测试、推理任务中接受数据并进行预测。分布式训练等情况下会被模型封装器（Model Wrapper，如 <code>MMDistributedDataParallel</code>）封装一层。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/optim_wrapper.html" target="_blank" rel="noreferrer">优化器封装（ Optimizer）</a>：负责在训练过程中执行反向传播优化模型，并以统一的接口支持混合精度训练和梯度累加。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/param_scheduler.html" target="_blank" rel="noreferrer">参数调度器（ Parameter Scheduler）</a>：在训练过程中对学习率、动量等优化器超参数进行动态调整。</li></ul><p>在训练间隙或测试阶段，<a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/evaluation.html" target="_blank" rel="noreferrer">评测指标与评测器（ Metrics &amp; Evaluator）</a>负责对模型性能进行评测。其中评测器负责基于数据集对模型的预测进行评估。评测器内还有一层抽象是评测指标，负责计算具体的一个或多个评测指标（如召回率、正确率等）。</p><p>为了统一接口， OpenMMLab 2.0 中各个算法库的评测器、模型和数据之间交流的接口都使用了<a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/data_element.html" target="_blank" rel="noreferrer">数据元素（ Data Element）</a>来进行封装。</p><p>在训练、推理执行过程中，上述各个组件都可以调用日志管理模块和可视化器进行结构化和非结构化日志的存储与展示。</p><ul><li><p><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/logging.html" target="_blank" rel="noreferrer">日志管理（ Logging Modules）</a>：负责管理执行器运行过程中产生的各种日志信息。其中消息枢纽（MessageHub）负责实现组件与组件、执行器与执行器之间的数据共享；日志处理器（Log Processor）负责对日志信息进行处理，处理后的日志会分别发送给执行器的日志器（Logger）和可视化器（Visualizer）进行日志的管理与展示。</p></li><li><p><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/visualization.html" target="_blank" rel="noreferrer">可视化器（ Visualizer）</a>：负责对模型的特征图、预测结果和训练过程中产生的结构化日志进行可视化，支持 TensorBoard 和 WandB 等多种可视化后端。</p></li></ul><h3 id="_2-2-公共基础模块" tabindex="-1">2.2 公共基础模块 <a class="header-anchor" href="#_2-2-公共基础模块" aria-label="Permalink to “2.2 公共基础模块”">​</a></h3><p>MMEngine 中还实现了各种算法模型执行过程中需要用到的公共基础模块，包括：</p><ul><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/config.html" target="_blank" rel="noreferrer">配置类（ Config）</a>：在 OpenMMLab 算法库中，用户可以通过编写 config 来配置训练、测试过程以及相关的组件。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/registry.html" target="_blank" rel="noreferrer">注册器（ Registry）</a>：负责管理算法库中具有相同功能的模块。MMEngine 根据对算法库模块的抽象，定义了一套根注册器，算法库中的注册器可以继承自这套根注册器，实现模块的跨算法库调用。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/fileio.html" target="_blank" rel="noreferrer">文件读写（ File I/O）</a>：为各个模块的文件读写提供了统一的接口，以统一的形式支持多种文件读写后端和多种文件格式，并具备扩展性。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/distributed.html" target="_blank" rel="noreferrer">分布式通信原语（ Distributed Communication Primitives）</a>：负责在程序分布式运行过程中不同进程间的通信。这套接口屏蔽了分布式和非分布式环境的区别，同时也自动处理了数据的设备和通信后端。</li><li><a href="https://mmengine.readthedocs.io/zh-cn/latest/advanced_tutorials/manager_mixin.html" target="_blank" rel="noreferrer">其他工具（ Utils）</a>：还有一些工具性的模块，如 ManagerMixin，它实现了一种全局变量的创建和获取方式，执行器内很多全局可见对象的基类就是 ManagerMixin。</li></ul><p>用户可以进一步阅读<a href="https://mmengine.readthedocs.io/zh-cn/latest/tutorials/runner.html" target="_blank" rel="noreferrer">教程</a>来了解这些模块的高级用法，也可以参考<a href="https://mmengine.readthedocs.io/zh-cn/latest/design/hook.html" target="_blank" rel="noreferrer">设计文档</a>了解它们的设计思路与细节。</p>`,18)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};